-- ============================================================
-- PROD MySQL MIGRATION v2 (no explicit BOM IDs)
-- Safe when prod IDs 6541-6930 are taken by other trailers.
-- Apply AFTER: file upload + restart.txt touch.
-- ============================================================
SET foreign_key_checks = 0;

-- 0. Ensure new columns exist (safe to re-run)
ALTER TABLE body_option_groups   ADD COLUMN IF NOT EXISTS parent_option_master_id INTEGER;
ALTER TABLE bom_sections         ADD COLUMN IF NOT EXISTS body_option_master_id   INTEGER;
ALTER TABLE bom_sections         ADD COLUMN IF NOT EXISTS archived_at             TIMESTAMP NULL;
ALTER TABLE trailer_types        ADD COLUMN IF NOT EXISTS configurator_v2         BOOLEAN NOT NULL DEFAULT 0;
ALTER TABLE bill_of_materials    ADD COLUMN IF NOT EXISTS selection_mode          VARCHAR(16) NOT NULL DEFAULT 'always';
ALTER TABLE bill_of_materials    ADD COLUMN IF NOT EXISTS selection_group         VARCHAR(100);
ALTER TABLE bill_of_materials    ADD COLUMN IF NOT EXISTS bom_conditions          TEXT;

-- 1. body_option_groups (upsert by id)

-- 2. bom_sections (ids 39, 40 — these are metadata rows, safe to upsert)

-- 3. configurator_v2
UPDATE trailer_types SET configurator_v2=1 WHERE id=51;

-- 4. Wipe existing trailer 51 BOM rows
DELETE FROM bill_of_materials WHERE trailer_type_id=51;

-- 5. Re-insert without explicit IDs (MySQL assigns new ones)

-- 6. Re-wire bom_sections.body_option_master_id via material-name lookup
--    (safe: only touches rows owned by trailer 51 masters)
UPDATE bom_sections SET body_option_master_id = (  SELECT MIN(b.id) FROM bill_of_materials b  JOIN materials mat ON mat.id=b.material_id  WHERE b.trailer_type_id=51 AND b.is_body_option=1 AND mat.name='SRD') WHERE id=2;  -- SRD -> SRD
UPDATE bom_sections SET body_option_master_id = (  SELECT MIN(b.id) FROM bill_of_materials b  JOIN materials mat ON mat.id=b.material_id  WHERE b.trailer_type_id=51 AND b.is_body_option=1 AND mat.name='SRD') WHERE id=3;  -- SRD DOOR FITTINGS -> SRD
UPDATE bom_sections SET body_option_master_id = (  SELECT MIN(b.id) FROM bill_of_materials b  JOIN materials mat ON mat.id=b.material_id  WHERE b.trailer_type_id=51 AND b.is_body_option=1 AND mat.name='DRD') WHERE id=4;  -- DRD -> DRD
UPDATE bom_sections SET body_option_master_id = (  SELECT MIN(b.id) FROM bill_of_materials b  JOIN materials mat ON mat.id=b.material_id  WHERE b.trailer_type_id=51 AND b.is_body_option=1 AND mat.name='DRD') WHERE id=5;  -- DRD DOOR FITTINGS -> DRD
UPDATE bom_sections SET body_option_master_id = (  SELECT MIN(b.id) FROM bill_of_materials b  JOIN materials mat ON mat.id=b.material_id  WHERE b.trailer_type_id=51 AND b.is_body_option=1 AND mat.name='2MM 3CR12 S/STEEL FLOOR') WHERE id=16;  -- 2MM 3CR12 S/STEEL FLOOR -> 2MM 3CR12 S/STEEL FLOOR
UPDATE bom_sections SET body_option_master_id = (  SELECT MIN(b.id) FROM bill_of_materials b  JOIN materials mat ON mat.id=b.material_id  WHERE b.trailer_type_id=51 AND b.is_body_option=1 AND mat.name='3MM MILD STEEL FLOOR') WHERE id=18;  -- 3MM MILD STEEL FLOOR -> 3MM MILD STEEL FLOOR
UPDATE bom_sections SET body_option_master_id = (  SELECT MIN(b.id) FROM bill_of_materials b  JOIN materials mat ON mat.id=b.material_id  WHERE b.trailer_type_id=51 AND b.is_body_option=1 AND mat.name='5MM 300 WA PLATE') WHERE id=19;  -- 5MM 300 WA PLATE -> 5MM 300 WA PLATE
UPDATE bom_sections SET body_option_master_id = (  SELECT MIN(b.id) FROM bill_of_materials b  JOIN materials mat ON mat.id=b.material_id  WHERE b.trailer_type_id=51 AND b.is_body_option=1 AND mat.name='4MM MILD STEEL FLOOR') WHERE id=31;  -- 4MM MILD STEEL FLOOR -> 4MM MILD STEEL FLOOR
UPDATE bom_sections SET body_option_master_id = (  SELECT MIN(b.id) FROM bill_of_materials b  JOIN materials mat ON mat.id=b.material_id  WHERE b.trailer_type_id=51 AND b.is_body_option=1 AND mat.name='24MM WISA TRANS FLOOR') WHERE id=38;  -- 24MM WISA TRANS FLOOR -> 24MM WISA TRANS FLOOR

-- 7. Re-wire body_option_groups.parent_option_master_id via material-name lookup
UPDATE body_option_groups SET parent_option_master_id = (  SELECT MIN(b.id) FROM bill_of_materials b  JOIN materials mat ON mat.id=b.material_id  WHERE b.trailer_type_id=51 AND b.is_body_option=1 AND mat.name='24MM WISA TRANS FLOOR') WHERE id=25;  -- FLOOR TYPE TOPPING -> 24MM WISA TRANS FLOOR
UPDATE body_option_groups SET parent_option_master_id = (  SELECT MIN(b.id) FROM bill_of_materials b  JOIN materials mat ON mat.id=b.material_id  WHERE b.trailer_type_id=51 AND b.is_body_option=1 AND mat.name='24MM WISA TRANS FLOOR') WHERE id=26;  -- FLOOR THICKNESS -> 24MM WISA TRANS FLOOR

SET foreign_key_checks = 1;

